import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Cpu, Lock, Mail, Eye, EyeOff } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!email || !password) {
      toast.error('Please enter email and password');
      return;
    }

    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back!');
      navigate('/dashboard');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Login failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center p-6">
      <div className="w-full max-w-md bg-[#141414] backdrop-blur-xl rounded-2xl border border-white/8 shadow-2xl overflow-hidden">
        {/* Ambient glow effect */}
        <div className="absolute -top-32 -left-32 w-64 h-64 bg-emerald-600/20 blur-[120px] pointer-events-none" />
        
        <div className="relative z-10 p-8 sm:p-10">
          {/* Header */}
          <div className="text-center mb-10">
            <div className="flex justify-center mb-6 text-emerald-400">
              <Cpu size={42} className="animate-pulse" />
            </div>
            <h1 className="text-3xl font-light tracking-tight text-white mb-2">
              Welcome Back
            </h1>
            <p className="text-white/40 text-xs uppercase tracking-widest font-mono">
              Sign in to access your account
            </p>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Email */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Mail size={14} /> Email
              </label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full p-4 rounded-xl bg-white/4 border border-white/8 text-white placeholder-white/20 outline-none transition-all duration-300 focus:border-emerald-500 focus:shadow-[0_0_0_1px_rgba(16,185,129,0.25)]"
                placeholder="you@example.com"
                required
              />
            </div>

            {/* Password */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Lock size={14} /> Password
              </label>
              <div className="relative">
                <input
                  type={showPassword ? "text" : "password"}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full p-4 rounded-xl bg-white/4 border border-white/8 text-white placeholder-white/20 outline-none transition-all duration-300 focus:border-emerald-500 focus:shadow-[0_0_0_1px_rgba(16,185,129,0.25)] pr-12"
                  placeholder="••••••••"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-white/40 hover:text-white/60 transition-colors"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {/* Submit */}
            <button
              type="submit"
              disabled={loading}
              className="w-full py-4 rounded-xl bg-emerald-500 font-semibold uppercase tracking-widest text-xs text-black transition-all duration-300 hover:bg-emerald-400 hover:shadow-[0_0_35px_rgba(16,185,129,0.3)] active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed mt-6"
            >
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>

          {/* Footer */}
          <div className="mt-10 pt-8 border-t border-white/5 text-center">
            <p className="text-xs text-white/40 uppercase tracking-widest">
              Don't have an account?{' '}
              <Link to="/register" className="text-emerald-400 hover:underline transition-colors">
                Sign Up
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
